const { z } = require('zod');

const Item = z.object({
  title: z.string().min(1),
  price: z.number().positive(),
  url: z.string().url(),
});

const raw = await page.locator('article.product').evaluateAll(els =>
  els.map(e => ({
    title: e.querySelector('h2')?.textContent?.trim(),
    price: parseFloat(e.querySelector('.price')?.textContent?.replace(/[^0-9.]/g, '')),
    url: e.querySelector('a')?.href,
  }))
);

const items = raw.map((r, i) => {
  const result = Item.safeParse(r);
  if (!result.success) console.error(`row ${i} skipped:`, result.error.flatten());
  return result.success ? result.data : null;
}).filter(Boolean);

// Next-button pagination
async function scrapeAllPages(page) {
  const allData = [];
  while (true) {
    const data = await page.$$eval('.item', items => items.map(i => i.textContent));
    allData.push(...data);
    const next = await page.$('a.next:not(.disabled)');
    if (!next) break;
    await Promise.all([page.waitForNavigation({ waitUntil: 'networkidle0' }), next.click()]);
  }
  return allData;
}

const pLimit = require('p-limit');
const limit = pLimit(3);

const tasks = urls.map(url =>
  limit(async () => {
    const page = await browser.newPage();
    try {
      await page.goto(url);
      return await extractData(page);
    } finally {
      await page.close();
    }
  })
);

return Promise.all(tasks);
